GRANT EXECUTE ON FUNCTION admin_create_reply(TEXT, UUID, TEXT, TEXT) TO anon, authenticated;
GRANT EXECUTE ON FUNCTION admin_delete_message(TEXT, UUID) TO anon, authenticated;
GRANT EXECUTE ON FUNCTION admin_delete_reply(TEXT, UUID) TO anon, authenticated;
GRANT EXECUTE ON FUNCTION admin_toggle_message_pin(TEXT, UUID, BOOLEAN) TO anon, authenticated;
GRANT EXECUTE ON FUNCTION admin_update_message_reaction_count(TEXT, UUID, TEXT, INTEGER) TO anon, authenticated;

COMMENT ON TABLE admin_sessions IS '后台管理员短期会话，前端只保存明文 token，数据库只保存 hash';
COMMENT ON TABLE admin_login_attempts IS '后台登录失败计数，用于数据库侧限速';


-- ============================================================================
-- 4. database/member_center_deployment_check.sql
-- sha256: ad53f2c009e0283d45072a3b06d94b98e2589f61f20f1066fb4ba58b236e7cb8
-- ============================================================================

-- Member center deployment check
-- Run after create_member_center_tables.sql and create_admin_member_session.sql.

WITH required_relations(name) AS (
  VALUES
    ('member_profiles'),
    ('member_subscriptions'),
    ('member_orders'),
    ('member_account_events'),
    ('member_identity_links'),
    ('member_identity_claims'),
    ('member_devices'),
    ('member_report_unlocks'),
    ('member_share_links'),
    ('admin_sessions'),
    ('admin_login_attempts')
),
required_functions(name) AS (
  VALUES
    ('get_or_create_member_profile'),
    ('link_member_identity'),
    ('register_legacy_identity_claim'),
    ('get_member_records'),
    ('update_member_profile'),
    ('register_member_device'),
    ('unlink_member_device'),
    ('create_member_order'),
    ('create_member_report_unlock'),
    ('create_member_share_link'),
    ('get_member_share_links'),
    ('deactivate_member_share_link'),
    ('get_member_public_share'),
    ('create_admin_session'),
    ('change_admin_password'),
    ('get_admin_session'),
    ('require_admin'),
    ('apply_member_order_approval'),
    ('member_admin_overview'),
    ('member_admin_members'),
    ('member_admin_orders'),
    ('member_admin_approve_order'),
    ('member_admin_reject_order'),
    ('admin_create_message'),
    ('admin_create_reply'),
    ('admin_delete_message'),
    ('admin_delete_reply'),
    ('admin_toggle_message_pin'),
    ('admin_update_message_reaction_count')
),
relation_check AS (
  SELECT
    name,
    EXISTS (
      SELECT 1
      FROM information_schema.tables
      WHERE table_schema = 'public' AND table_name = name
    ) AS ok
  FROM required_relations
),
function_check AS (
  SELECT
    name,
    EXISTS (
      SELECT 1
      FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = 'public' AND p.proname = name
    ) AS ok
  FROM required_functions
),
rls_check AS (
  SELECT
    c.relname AS name,
    c.relrowsecurity AS ok
  FROM pg_class c
  JOIN pg_namespace n ON n.oid = c.relnamespace
  WHERE n.nspname = 'public'
    AND c.relname IN (
      'member_profiles',
      'member_subscriptions',
      'member_orders',
      'member_account_events',
      'member_identity_links',
      'member_identity_claims',
      'member_devices',
      'member_report_unlocks',
      'member_share_links',
      'admin_sessions',
      'admin_login_attempts'
    )
),
security_policy_check AS (
  SELECT
    'old_link_member_identity_signature_removed' AS name,
    to_regprocedure('public.link_member_identity(text, text)') IS NULL AS ok
  UNION ALL
  SELECT
    'old_get_or_create_member_profile_signature_removed' AS name,
    to_regprocedure('public.get_or_create_member_profile(text, text)') IS NULL AS ok
  UNION ALL
  SELECT
    'old_register_member_device_signature_removed' AS name,
    to_regprocedure('public.register_member_device(text, text, text)') IS NULL AS ok
  UNION ALL
  SELECT
    'member_identity_claims_no_read_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_identity_claims'
        AND policyname = 'member_identity_claims_no_read'
    ) AS ok
  UNION ALL
  SELECT
    'member_identity_claims_not_selectable' AS name,
    NOT has_table_privilege('authenticated', 'member_identity_claims', 'SELECT')
      AND NOT has_table_privilege('anon', 'member_identity_claims', 'SELECT') AS ok
  UNION ALL
  SELECT
    'member_identity_links_no_owner_insert_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_identity_links'
        AND policyname = 'member_identity_links_owner_insert'
    ) AS ok
  UNION ALL
  SELECT
    'member_identity_links_no_owner_update_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_identity_links'
        AND policyname = 'member_identity_links_owner_update'
    ) AS ok
  UNION ALL
  SELECT
    'member_identity_links_no_owner_delete_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_identity_links'
        AND policyname = 'member_identity_links_owner_delete'
    ) AS ok
  UNION ALL
  SELECT
    'member_identity_links_write_not_granted' AS name,
    NOT has_table_privilege('authenticated', 'member_identity_links', 'INSERT')
      AND NOT has_table_privilege('authenticated', 'member_identity_links', 'UPDATE')
      AND NOT has_table_privilege('authenticated', 'member_identity_links', 'DELETE') AS ok
  UNION ALL
  SELECT
    'member_profiles_no_owner_insert_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_profiles'
        AND policyname = 'member_profiles_owner_insert'
    ) AS ok
  UNION ALL
  SELECT
    'member_profiles_no_owner_update_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_profiles'
        AND policyname = 'member_profiles_owner_update'
    ) AS ok
  UNION ALL
  SELECT
    'member_share_links_no_public_select_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_share_links'
        AND policyname = 'member_share_links_public_read_active'
    ) AS ok
  UNION ALL
  SELECT
    'member_devices_no_owner_insert_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_devices'
        AND policyname = 'member_devices_owner_insert'
    ) AS ok
  UNION ALL
  SELECT
    'member_account_events_no_owner_insert_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_account_events'
        AND policyname = 'member_account_events_owner_insert'
    ) AS ok
  UNION ALL
  SELECT
    'member_devices_no_owner_update_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_devices'
        AND policyname = 'member_devices_owner_update'
    ) AS ok
  UNION ALL
  SELECT
    'member_devices_delete_not_granted' AS name,
    NOT has_table_privilege('authenticated', 'member_devices', 'DELETE') AS ok
  UNION ALL
  SELECT
    'member_share_links_no_owner_read_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_share_links'
        AND policyname = 'member_share_links_owner_read'
    ) AS ok
  UNION ALL
  SELECT
    'member_orders_no_owner_insert_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_orders'
        AND policyname = 'member_orders_owner_insert'
    ) AS ok
  UNION ALL
  SELECT
    'member_report_unlocks_no_owner_insert_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_report_unlocks'
        AND policyname = 'member_report_unlocks_owner_insert'
    ) AS ok
  UNION ALL
  SELECT
    'member_share_links_no_owner_insert_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_share_links'
        AND policyname = 'member_share_links_owner_insert'
    ) AS ok
  UNION ALL
  SELECT
    'member_share_links_no_owner_update_policy' AS name,
    NOT EXISTS (
      SELECT 1
      FROM pg_policies
      WHERE schemaname = 'public'
        AND tablename = 'member_share_links'
        AND policyname = 'member_share_links_owner_update'
    ) AS ok
  UNION ALL
  SELECT
    'member_share_links_hash_not_selectable_by_authenticated' AS name,
    NOT has_column_privilege('authenticated', 'member_share_links', 'access_code_hash', 'SELECT') AS ok
  UNION ALL
  SELECT
    'member_share_links_hash_not_selectable_by_anon' AS name,
    NOT has_column_privilege('anon', 'member_share_links', 'access_code_hash', 'SELECT') AS ok
  UNION ALL
  SELECT
    'verify_admin_password_not_executable_by_anon' AS name,
    NOT has_function_privilege('anon', 'verify_admin_password(text)', 'EXECUTE') AS ok
  UNION ALL
  SELECT
    'get_admin_session_not_executable_by_anon' AS name,
    NOT has_function_privilege('anon', 'get_admin_session(text)', 'EXECUTE') AS ok
  UNION ALL
  SELECT
    'require_admin_not_executable_by_anon' AS name,
    NOT has_function_privilege('anon', 'require_admin(text)', 'EXECUTE') AS ok
  UNION ALL
  SELECT
    'apply_member_order_approval_not_executable_by_anon' AS name,
    NOT has_function_privilege('anon', 'apply_member_order_approval(uuid, text, text, text, text)', 'EXECUTE') AS ok
  UNION ALL
  SELECT
    'admin_message_delete_rpc_exists' AS name,
    has_function_privilege('anon', 'admin_delete_message(text, uuid)', 'EXECUTE') AS ok
  UNION ALL
  SELECT
    'admin_message_create_rpc_exists' AS name,
    has_function_privilege('anon', 'admin_create_message(text, text, text)', 'EXECUTE') AS ok
  UNION ALL
  SELECT
    'admin_message_pin_rpc_exists' AS name,
    has_function_privilege('anon', 'admin_toggle_message_pin(text, uuid, boolean)', 'EXECUTE') AS ok
  UNION ALL
  SELECT
    'admin_login_attempts_rls_enabled' AS name,
    COALESCE((
      SELECT c.relrowsecurity
      FROM pg_class c
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname = 'public' AND c.relname = 'admin_login_attempts'
    ), false) AS ok
  UNION ALL
  SELECT
    'member_subscriptions_provider_ref_unique_index' AS name,
    EXISTS (
      SELECT 1
      FROM pg_indexes
      WHERE schemaname = 'public'
        AND tablename = 'member_subscriptions'
        AND indexname = 'idx_member_subscriptions_provider_ref_unique'
    ) AS ok
  UNION ALL
  SELECT
    'member_orders_provider_ref_unique_index' AS name,
    EXISTS (
      SELECT 1
      FROM pg_indexes
      WHERE schemaname = 'public'
        AND tablename = 'member_orders'
        AND indexname = 'idx_member_orders_provider_ref_unique'
    ) AS ok
)
SELECT 'table' AS check_type, name, ok FROM relation_check
UNION ALL
SELECT 'function' AS check_type, name, ok FROM function_check
UNION ALL
SELECT 'rls' AS check_type, name, ok FROM rls_check
UNION ALL
SELECT 'security' AS check_type, name, ok FROM security_policy_check
ORDER BY check_type, name;


-- ============================================================================
-- 5. database/member_center_e2e_check.sql
-- sha256: 3e827df2b00469ed5935cd309010b37b6430b4a1143720e2e759740171959b37
-- ============================================================================

-- Member center end-to-end database check
-- Run after create_member_center_tables.sql and create_admin_member_session.sql.
-- This script creates temporary test data, validates the member RPC flow, and cleans up.

CREATE TEMP TABLE IF NOT EXISTS member_center_e2e_results (
  step_order INTEGER NOT NULL,
  name TEXT NOT NULL,
  ok BOOLEAN NOT NULL,
  detail TEXT NOT NULL
);

TRUNCATE member_center_e2e_results;

DO $$
DECLARE
  test_account_id UUID := gen_random_uuid();
  test_legacy_id TEXT := 'codex-member-e2e-' || replace(gen_random_uuid()::text, '-', '');
  test_claim_secret TEXT := replace(gen_random_uuid()::text, '-', '') || replace(gen_random_uuid()::text, '-', '');
  test_second_legacy_id TEXT := 'codex-member-e2e-second-' || replace(gen_random_uuid()::text, '-', '');
  test_second_claim_secret TEXT := replace(gen_random_uuid()::text, '-', '') || replace(gen_random_uuid()::text, '-', '');
  test_share_token TEXT := 'codex-e2e-' || replace(gen_random_uuid()::text, '-', '');
  test_record_id UUID;
  test_second_record_id UUID;
  test_order_id UUID;
  test_device_id UUID;
  profile_row member_profiles%ROWTYPE;
  device_row member_devices%ROWTYPE;
  order_row member_orders%ROWTYPE;
  unlock_row member_report_unlocks%ROWTYPE;
  approval_result JSONB;
  share_result JSONB;
  share_list JSONB;
  public_gate JSONB;
  public_report JSONB;
  member_records JSONB;
  wrong_claim_failed BOOLEAN := false;
  inactive_failed BOOLEAN := false;
BEGIN
  PERFORM set_config('request.jwt.claim.sub', test_account_id::text, true);
  PERFORM set_config('request.jwt.claim.role', 'authenticated', true);

  INSERT INTO test_records (user_id_text, test_type, report_data, created_at)
  VALUES (
    test_legacy_id,
    'female',
    jsonb_build_object('completedItems', 3, 'totalItems', 3),
    timezone('utc'::text, now())
  )
  RETURNING id INTO test_record_id;

  INSERT INTO test_results (record_id, category, item, rating, created_at)
  VALUES
    (test_record_id, 'SSS 控制', '边界确认', 'SSS', timezone('utc'::text, now())),
    (test_record_id, 'SS 感官', '沟通偏好', 'SS', timezone('utc'::text, now())),
    (test_record_id, 'N 禁区', '明确拒绝', 'N', timezone('utc'::text, now()));

  INSERT INTO member_center_e2e_results
  VALUES (10, 'seed_test_record', test_record_id IS NOT NULL, 'created temporary test_records/test_results rows');

  PERFORM register_legacy_identity_claim(test_legacy_id, test_claim_secret);

  SELECT * INTO profile_row
  FROM get_or_create_member_profile(test_legacy_id, 'Codex E2E Member', test_claim_secret);

  INSERT INTO member_center_e2e_results
  VALUES (
    20,
    'get_or_create_member_profile',
    profile_row.account_id = test_account_id
      AND profile_row.legacy_user_id_text = test_legacy_id
      AND profile_row.membership_tier = 'free',
    'profile created and bound to simulated auth.uid()'
  );

  SELECT * INTO profile_row
  FROM update_member_profile(
    'Codex E2E Updated',
    '{"hideUserId": true, "hideSensitiveItems": true, "allowPrivateShare": true}'::jsonb,
    '{"monthlySummary": true, "trendReminder": true}'::jsonb
  );

  INSERT INTO member_center_e2e_results
  VALUES (
    30,
    'update_member_profile',
    profile_row.display_name = 'Codex E2E Updated'
      AND profile_row.notification_settings->>'trendReminder' = 'true',
    'profile display name and notification settings updated'
  );

  INSERT INTO test_records (user_id_text, test_type, report_data, created_at)
  VALUES (
    test_second_legacy_id,
    'male',
    jsonb_build_object('completedItems', 1, 'totalItems', 1),
    timezone('utc'::text, now()) + interval '1 minute'
  )
  RETURNING id INTO test_second_record_id;

  INSERT INTO test_results (record_id, category, item, rating, created_at)
  VALUES (test_second_record_id, 'SSS 主导', '跨设备记录', 'SSS', timezone('utc'::text, now()));

  PERFORM register_legacy_identity_claim(test_second_legacy_id, test_second_claim_secret);
  BEGIN
    PERFORM link_member_identity(test_second_legacy_id, 'wrong-secret-for-e2e', 'Wrong Claim');
  EXCEPTION WHEN OTHERS THEN
    wrong_claim_failed := true;
  END;

  INSERT INTO member_center_e2e_results
  VALUES (
    34,
    'link_member_identity_rejects_wrong_secret',
    wrong_claim_failed,
    'member identity cannot be linked without the local identity secret'
  );

  PERFORM link_member_identity(test_second_legacy_id, test_second_claim_secret, 'Codex E2E Second Device');
  member_records := get_member_records();

  INSERT INTO member_center_e2e_results
  VALUES (
    35,
    'get_member_records_cross_identity',
    jsonb_path_exists(member_records, ('$[*] ? (@.id == "' || test_record_id || '")')::jsonpath)
      AND jsonb_path_exists(member_records, ('$[*] ? (@.id == "' || test_second_record_id || '")')::jsonpath),
    'member account reads records from all linked legacy identities'
  );

  SELECT * INTO device_row
  FROM register_member_device(test_legacy_id, test_claim_secret, 'Codex E2E Device', repeat('a', 64));
  test_device_id := device_row.id;

  INSERT INTO member_center_e2e_results
  VALUES (
    40,
    'register_member_device',
    device_row.account_id = test_account_id
      AND device_row.user_agent_hash = repeat('a', 64),
    'device registered for simulated member'
  );

  SELECT * INTO order_row
  FROM create_member_order(test_legacy_id, 'premium_monthly', 'codex-e2e@example.test', 'database e2e check');
  test_order_id := order_row.id;

  INSERT INTO member_center_e2e_results
  VALUES (
    50,
    'create_member_order',
    order_row.status = 'pending'
      AND order_row.amount_cents = 3900
      AND order_row.account_id = test_account_id,
    'premium monthly pending order created'
  );

  approval_result := apply_member_order_approval(
    test_order_id,
    'codex_e2e',
    test_order_id::text,
    'database e2e approval',
    'codex_e2e_order_approved'
  );

  INSERT INTO member_center_e2e_results
  VALUES (
    60,
    'apply_member_order_approval',
    approval_result->>'ok' = 'true'
      AND approval_result->>'tier' = 'premium'
      AND EXISTS (
        SELECT 1
        FROM member_profiles
        WHERE account_id = test_account_id
          AND membership_tier = 'premium'
      )
      AND EXISTS (
        SELECT 1
        FROM member_subscriptions
        WHERE account_id = test_account_id
          AND status = 'active'
          AND provider = 'codex_e2e'
          AND provider_ref = test_order_id::text
      ),
    'order approval updated profile tier and active subscription'
  );

  SELECT * INTO unlock_row
  FROM create_member_report_unlock(test_legacy_id, test_record_id, 'advanced_report');

  INSERT INTO member_center_e2e_results
  VALUES (
    70,
    'create_member_report_unlock',
    unlock_row.account_id = test_account_id
      AND unlock_row.record_id = test_record_id
      AND unlock_row.unlock_type = 'advanced_report',
    'premium account unlocked advanced report for owned record'
  );

  share_result := create_member_share_link(
    test_legacy_id,
    test_record_id,
    'Codex E2E Share',
    'correct-code',
    '["items"]'::jsonb,
    timezone('utc'::text, now()) + interval '1 day',
    test_share_token
  );

  INSERT INTO member_center_e2e_results
  VALUES (
    80,
    'create_member_share_link',
    share_result->>'share_token' = test_share_token
      AND NOT (share_result ? 'access_code_hash'),
    'share link created without exposing access_code_hash'
  );

  share_list := get_member_share_links();

  INSERT INTO member_center_e2e_results
  VALUES (
    90,
    'get_member_share_links',
    jsonb_path_exists(share_list, ('$[*] ? (@.share_token == "' || test_share_token || '")')::jsonpath)
      AND position('access_code_hash' in share_list::text) = 0,
    'member share list includes token and does not expose access hash'
  );

  public_gate := get_member_public_share(test_share_token, NULL);

  INSERT INTO member_center_e2e_results
  VALUES (
    100,
    'get_member_public_share_requires_password',
    public_gate->>'requiresAccessCode' = 'true'
      AND NOT (public_gate ? 'record'),
    'public share requires access code before showing record'
  );

  public_gate := get_member_public_share(test_share_token, 'wrong-code');

  INSERT INTO member_center_e2e_results
  VALUES (
    110,
    'get_member_public_share_rejects_wrong_password',
    public_gate->>'requiresAccessCode' = 'true'
      AND NOT (public_gate ? 'record'),
    'wrong access code keeps report hidden'
  );

  public_report := get_member_public_share(test_share_token, 'correct-code');

  INSERT INTO member_center_e2e_results
  VALUES (
    120,
    'get_member_public_share_accepts_password',
    public_report->>'requiresAccessCode' = 'false'
      AND public_report->'record'->>'id' = test_record_id::text
      AND jsonb_array_length(public_report->'record'->'details') = 3
      AND (public_report->'link'->'hidden_sections') ? 'items',
    'correct access code returns report details and hidden section metadata'
  );

  INSERT INTO member_center_e2e_results
  VALUES (
    130,
    'deactivate_member_share_link',
    (deactivate_member_share_link((share_result->>'id')::uuid)->>'is_active') = 'false',
    'member can deactivate own share link'
  );

  BEGIN
    PERFORM get_member_public_share(test_share_token, 'correct-code');
  EXCEPTION WHEN OTHERS THEN
    inactive_failed := true;
  END;

  INSERT INTO member_center_e2e_results
  VALUES (
    140,
    'deactivated_share_is_not_public',
    inactive_failed,
    'deactivated share cannot be read publicly'
  );

  INSERT INTO member_center_e2e_results
  VALUES (
    150,
    'unlink_member_device',
    unlink_member_device(test_device_id),
    'member can unlink own device'
  );

  DELETE FROM member_share_links WHERE account_id = test_account_id;
  DELETE FROM member_report_unlocks WHERE account_id = test_account_id;
  DELETE FROM member_subscriptions WHERE account_id = test_account_id;
  DELETE FROM member_orders WHERE account_id = test_account_id;
  DELETE FROM member_devices WHERE account_id = test_account_id;
  DELETE FROM member_identity_links WHERE account_id = test_account_id;
  DELETE FROM member_account_events WHERE account_id = test_account_id;
  DELETE FROM member_profiles WHERE account_id = test_account_id;
  DELETE FROM member_identity_claims WHERE legacy_user_id_text IN (test_legacy_id, test_second_legacy_id);
  DELETE FROM test_results WHERE record_id = test_record_id;
  DELETE FROM test_records WHERE id = test_record_id;
  DELETE FROM test_results WHERE record_id = test_second_record_id;
  DELETE FROM test_records WHERE id = test_second_record_id;

  INSERT INTO member_center_e2e_results
  VALUES (
    160,
    'cleanup',
    NOT EXISTS (SELECT 1 FROM member_profiles WHERE account_id = test_account_id)
      AND NOT EXISTS (SELECT 1 FROM test_records WHERE id = test_record_id)
      AND NOT EXISTS (SELECT 1 FROM test_records WHERE id = test_second_record_id),
    'temporary member and test record data removed'
  );
EXCEPTION WHEN OTHERS THEN
  DELETE FROM member_share_links WHERE account_id = test_account_id;
  DELETE FROM member_report_unlocks WHERE account_id = test_account_id;
  DELETE FROM member_subscriptions WHERE account_id = test_account_id;
  DELETE FROM member_orders WHERE account_id = test_account_id;
  DELETE FROM member_devices WHERE account_id = test_account_id;
  DELETE FROM member_identity_links WHERE account_id = test_account_id;
  DELETE FROM member_account_events WHERE account_id = test_account_id;
  DELETE FROM member_profiles WHERE account_id = test_account_id;
  DELETE FROM member_identity_claims WHERE legacy_user_id_text IN (test_legacy_id, test_second_legacy_id);
  IF test_record_id IS NOT NULL THEN
    DELETE FROM test_results WHERE record_id = test_record_id;
    DELETE FROM test_records WHERE id = test_record_id;
  END IF;
  IF test_second_record_id IS NOT NULL THEN
    DELETE FROM test_results WHERE record_id = test_second_record_id;
    DELETE FROM test_records WHERE id = test_second_record_id;
  END IF;

  INSERT INTO member_center_e2e_results
  VALUES (999, 'unexpected_error', false, SQLERRM);
END;
$$;

SELECT step_order, name, ok, detail
FROM member_center_e2e_results
ORDER BY step_order;
